-- Migration: Re-create pathway phases comprehensively with richly detailed Dynamic Prompts

DROP TABLE IF EXISTS public.mind_coach_pathway_phases;

CREATE TABLE public.mind_coach_pathway_phases (
    id TEXT PRIMARY KEY,
    pathway_name TEXT NOT NULL,
    pathway_description TEXT NOT NULL,
    phase_number INT NOT NULL,
    phase_name TEXT NOT NULL,
    phase_description TEXT NOT NULL,
    therapist_step TEXT NOT NULL,
    dynamic_prompt TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

ALTER TABLE public.mind_coach_pathway_phases ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read pathway phases" ON public.mind_coach_pathway_phases FOR SELECT USING (true);

ON CONFLICT (id) DO UPDATE SET dynamic_prompt = EXCLUDED.dynamic_prompt, therapist_step = EXCLUDED.therapist_step;
